        n = len(nums)
        prefix = [0] * n
        suffix = [0] * n

        prefix[0] = 0
        for i in range(1, n):
            prefix[i] = prefix[i-1] | nums[i-1]

        suffix[-1] = 0
        for i in range(n-2, -1, -1):
